+import type { AnyColumn } from '../../column.ts';
+import type { SQL, SQLWrapper } from '../sql.ts';
+import { sql } from '../sql.ts';
+
+type WindowValue<T> = T extends SQL<infer TValue> ? TValue : T extends AnyColumn ? T['_']['data'] : unknown;
+type WindowArgument = AnyColumn | SQLWrapper;
+
+export type FrameBoundary =
+	| { readonly kind: 'unbounded preceding' }
+	| { readonly kind: 'current row' }
+	| { readonly kind: 'unbounded following' }
+	| { readonly kind: 'preceding'; readonly value: number }
+	| { readonly kind: 'following'; readonly value: number };
+
+export const unboundedPreceding: FrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: FrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: FrameBoundary = { kind: 'unbounded following' };
+
+function offsetBoundary(kind: 'preceding' | 'following', value: number): FrameBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${kind}() requires a non-negative integer, received ${value}`);
+	}
+	return { kind, value };
+}
+
+export function preceding(value: number): FrameBoundary {
+	return offsetBoundary('preceding', value);
+}
+
+export function following(value: number): FrameBoundary {
+	return offsetBoundary('following', value);
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: FrameBoundary;
+	readonly to: FrameBoundary;
+}
+
+function boundaryPosition(boundary: FrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function createFrame(type: WindowFrame['type'], spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be after the "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return createFrame('rows', spec);
+}
+
+export function range(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return createFrame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: WindowArgument | WindowArgument[];
+	orderBy?: WindowArgument | WindowArgument[];
+	frame?: WindowFrame;
+}
+
+function frameBoundarySql(boundary: FrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'preceding': return sql.raw(`${boundary.value} preceding`);
+		case 'following': return sql.raw(`${boundary.value} following`);
+		default: return sql.raw(boundary.kind);
+	}
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) {
+		parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	}
+	if (spec.frame) {
+		parts.push(sql`${sql.raw(spec.frame.type)} between ${frameBoundarySql(spec.frame.from)} and ${frameBoundarySql(spec.frame.to)}`);
+	}
+	return sql.join(parts, sql` `);
+}
+
+export class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec?: WindowSpec | string): SQL<T> {
+		if (typeof spec === 'string') return sql`${this.expression} over ${sql.identifier(spec)}`;
+		return sql`${this.expression} over (${buildWindowSpec(spec ?? {})})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positiveInteger(functionName: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${functionName}() requires a positive integer, received ${value}`);
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return windowFunction('ntile', [sql.raw(String(buckets))]); }
+
+function valueFunction<T extends WindowArgument>(name: string, value: T, args: SQLWrapper[] = []): WindowFunction<WindowValue<T> | null> {
+	return windowFunction(name, [value, ...args]);
+}
+
+export function lag<T extends WindowArgument>(value: T, offset?: number): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends WindowArgument, TDefault>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<WindowValue<T> | TDefault>;
+export function lag(value: WindowArgument, offset?: number, defaultValue?: unknown): WindowFunction<unknown> {
+	const args: SQLWrapper[] = [value];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (arguments.length > 2) args.push(sql`${defaultValue}`);
+	return windowFunction('lag', args);
+}
+
+export function lead<T extends WindowArgument>(value: T, offset?: number): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends WindowArgument, TDefault>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<WindowValue<T> | TDefault>;
+export function lead(value: WindowArgument, offset?: number, defaultValue?: unknown): WindowFunction<unknown> {
+	const args: SQLWrapper[] = [value];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (arguments.length > 2) args.push(sql`${defaultValue}`);
+	return windowFunction('lead', args);
+}
+
+export function firstValue<T extends WindowArgument>(value: T): WindowFunction<WindowValue<T> | null> { return valueFunction('first_value', value); }
+export function lastValue<T extends WindowArgument>(value: T): WindowFunction<WindowValue<T> | null> { return valueFunction('last_value', value); }
+export function nthValue<T extends WindowArgument>(value: T, nth: number): WindowFunction<WindowValue<T> | null> { positiveInteger('nthValue', nth); return valueFunction('nth_value', value, [sql.raw(String(nth))]); }
+
+export function windowSum<T extends WindowArgument>(value: T): WindowFunction<number | null> { return valueFunction('sum', value); }
+export function windowAvg<T extends WindowArgument>(value: T): WindowFunction<number | null> { return valueFunction('avg', value); }
+export function windowMin<T extends WindowArgument>(value: T): WindowFunction<WindowValue<T> | null> { return valueFunction('min', value); }
+export function windowMax<T extends WindowArgument>(value: T): WindowFunction<WindowValue<T> | null> { return valueFunction('max', value); }
+export function windowCount(): WindowFunction<number>;
+export function windowCount<T extends WindowArgument>(value: T): WindowFunction<number>;
+export function windowCount(value?: WindowArgument): WindowFunction<number> { return windowFunction('count', value ? [value] : [sql.raw('*')]); }
